import{_ as t,o as e,c as n,ag as r}from"./chunks/framework.6MCaaFDc.js";const g=JSON.parse('{"title":"Data & Information Management","description":"","frontmatter":{"title":"Data & Information Management","parent":"Theory (Paper 2)","nav_order":4,"has_children":true},"headers":[],"relativePath":"theory/databases/index.md","filePath":"theory/databases/index.md"}'),i={name:"theory/databases/index.md"};function o(s,a,d,l,h,m){return e(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="data-information-management" tabindex="-1">Data &amp; Information Management <a class="header-anchor" href="#data-information-management" aria-label="Permalink to &quot;Data &amp; Information Management&quot;">​</a></h1><p>This topic covers the theory behind how data is stored, organised and managed using databases. Students learn how to design a well-structured relational database, how to apply normalisation rules, and how to ensure data quality through integrity constraints. The practical application of SQL is covered in the Practical section; this section focuses on the underlying concepts.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./data-concepts.html">Data Concepts</a></td><td>Data vs information, data types, data quality, metadata</td></tr><tr><td><a href="./database-concepts.html">Database Concepts</a></td><td>What a database is, flat-file vs relational databases, DBMS, key terms</td></tr><tr><td><a href="./database-design.html">Database Design</a></td><td>Entity-relationship (ER) diagrams, primary keys, foreign keys, relationships</td></tr><tr><td><a href="./normalisation.html">Normalisation</a></td><td>1NF, 2NF, 3NF — understanding and applying normal forms</td></tr><tr><td><a href="./data-integrity.html">Data Integrity</a></td><td>Entity integrity, referential integrity, domain integrity, validation rules</td></tr><tr><td><a href="./sql-theory.html">SQL Theory</a></td><td>Purpose of SQL, DML vs DDL vs DQL, overview of SQL commands</td></tr><tr><td><a href="./dbms-software.html">DBMS Software</a></td><td>Examples of DBMS software, roles of a DBA, advantages of using a DBMS</td></tr></tbody></table><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>Data &amp; Information Management is assessed in <strong>Paper 2</strong> across all grades.</p><ul><li><strong>Grade 10</strong> — Data types, flat-file vs relational concepts, basic database terminology.</li><li><strong>Grade 11</strong> — ER diagrams, primary and foreign keys, introductory normalisation.</li><li><strong>Grade 12</strong> — Full normalisation to 3NF, data integrity, SQL theory, DBMS roles and features.</li></ul>',7)])])}const f=t(i,[["render",o]]);export{g as __pageData,f as default};
